#include<bits/stdc++.h>
using namespace std;
int m,q,res[100010];
char s[2000010];
int getnum(int p,int &x)
{
    x=0;
    while(isdigit(s[p]))
    {
        x=x*10+(s[p]-'0');
        p++;
    }
    return p;
}
int calc(int p,int l,int r)
{
    if(isdigit(s[p]))
    {
        int tmp;
        int ans=getnum(p,tmp);
        for(int i=l;i<=r;i++)
        {
            res[i]=tmp;
        }
        return ans;
    }
    int a;
    int b=getnum(p+2,a);
    if(s[p+1]=='>')
    {
        int c=calc(b+1,a+1,r);
        return calc(c+1,l,a);
    }
    else
    {
        int c=calc(b+1,l,a-1);
        return calc(c+1,a,r);
    }
}
int main()
{
    scanf("%d%d%s",&m,&q,&s);
    calc(0,1,m+1);
    while(q--)
    {
        int x;
        scanf("%d",&x);
        printf("%d\n",res[min(m+1,x)]);
    }
    return 0;
}
